 * REGRESSION — FRG-209
 * Verifies the "talk" action type and character-to-character conversation mechanics.
 *
 * The AI engine can return four action types: move, interact, idle, talk.
 * When "talk" is returned the character approaches another character and
 * dialogue is exchanged (visible via pendingSpeech / currentDialogue).
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine, pollEngineState } = require('../helpers');

test.describe('Regression: Talk action and character-to-character conversation', () => {
  test('LLM decisions include "talk" in the set of valid action types', async ({ page }) => {
    /**
     * Extend the valid action set from FRG-184 (move|interact|idle) to include "talk".
     * We observe responses over two full AI cycles (≈65 s) for maximum coverage.
     * At least one character should decide to talk given enough time.
     */
    test.setTimeout(90_000);

    const decisions = [];

    page.on('response', async res => {
      if (res.url().includes('/api/llm') && res.request().method() === 'POST') {
        try {
          const json = await res.json();
          const text = json?.content?.[0]?.text ?? json?.choices?.[0]?.message?.content;
          if (text) decisions.push(JSON.parse(text));
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
