'use strict';
/**
 * REGRESSION — FRG-209
 * Verifies:
 *  1. AI decision cycle re-fires after 30 real seconds (second cycle)
 *  2. Characters remain at objects for the expected activity duration
 *  3. Object timers (stove, bonsai, etc.) respect configured durations
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine, getEngineState, pollEngineState } = require('../helpers');

test.describe('Regression: Activity duration and 30-second AI cycle', () => {
  test('AI decision cycle re-fires after ~30s — second wave of LLM requests', async ({ page }) => {
    /**
     * Each character should fire exactly one LLM request per 30-second cycle.
     * After ~65s we expect: 6 total requests (2 per character × 3 characters).
     * This verifies the rescheduling / timer logic after the first decision fires.
     */
    test.setTimeout(90_000);

    const byChar = new Map();

    page.on('request', req => {
      if (req.url().includes('/api/llm') && req.method() === 'POST') {
        try {
          const body = JSON.parse(req.postData() || '{}');
          const match = (body.system || '').match(/You are (Maple|Sol|Nyx)/);
          if (match) {
            const name = match[1];
            byChar.set(name, (byChar.get(name) || 0) + 1);
          }
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
    await waitForEngine(page);

    // Wait for two full 30-second cycles (with 5s margin)
    await page.waitForTimeout(65_000);

    // Each of the 3 characters should have fired at least twice
    expect(byChar.size, 'All 3 characters must have sent requests').toBe(3);
    for (const [name, count] of byChar) {
      expect(
        count,
        `${name} sent ${count} request(s) — expected ≥2 across 65s (two 30s cycles)`
      ).toBeGreaterThanOrEqual(2);
    }

    console.log('LLM request counts per character:', Object.fromEntries(byChar));
  });

  test('stove object stays in active state for ~30 seconds before returning to idle', async ({ page }) => {
    /**
     * The stove's activity duration is 30 real seconds.
     * Trigger it via the engine and verify it doesn't auto-reset prematurely.
     */
    test.setTimeout(90_000);

    await page.goto('/');
    await waitForEngine(page);

    // Manually trigger the stove via the engine
    await page.evaluate(() => {
      window._gameEngine.objectEngine.interact('stove', 'use');
    });

    // Verify stove transitioned to an active state (not idle)
    await page.waitForTimeout(500);
    const activated = await getEngineState(page);
    const stove = activated.objectStates.find(o => o.id === 'stove');
    expect(stove?.state, 'Stove should enter active state after interact').not.toBe('idle');
    console.log(`Stove state after trigger: ${stove?.state}`);

    // Check at 20s — stove must still be active (not yet auto-reset)
    await page.waitForTimeout(20_000);
    const midCheck = await getEngineState(page);
    const stoveMid = midCheck.objectStates.find(o => o.id === 'stove');
    expect(
      stoveMid?.state,
      'Stove returned to idle before 30s — auto_next timer too short'
    ).not.toBe('idle');
    console.log(`Stove state at 20s: ${stoveMid?.state}`);

    // Wait for auto-reset (up to 45s total)
    const returned = await pollEngineState(
      page,
      state => state.objectStates.find(o => o.id === 'stove')?.state === 'idle',
      45_000,
      1000
    );
    const stoveAfter = returned.objectStates.find(o => o.id === 'stove');
    expect(stoveAfter.state, 'Stove should return to idle after activity duration').toBe('idle');
    console.log('Stove returned to idle as expected.');
  });

  test('interacting character stays near object tile during activity', async ({ page }) => {
    /**
     * When a character is interacting with an object, their tile position should
     * remain close to the object's tile (within 2 tiles) for the duration of the interaction.
     * We monitor the bonsai interaction since it completes quickly (12s).
     */
    test.setTimeout(60_000);

    await page.goto('/');
    await waitForEngine(page);

    // Trigger the bonsai interaction
    await page.evaluate(() => {
      window._gameEngine.objectEngine.interact('bonsai', 'use');
    });

    // Poll until a character is in an interact-like action (not walking)
    // Sample character positions every 2s while bonsai is active
    const positionSamples = [];

    for (let i = 0; i < 5; i++) {
      await page.waitForTimeout(1500);
      const state = await getEngineState(page);
      const bonsai = state.objectStates.find(o => o.id === 'bonsai');
      if (bonsai?.state === 'idle') break; // auto-reset already happened
      positionSamples.push(state.characters.map(c => ({ label: c.label, tx: c.tx, ty: c.ty, action: c.action })));
    }

    console.log('Character position samples during bonsai interaction:', JSON.stringify(positionSamples, null, 2));

    // Verify all sampled positions are within walkable bounds
    for (const sample of positionSamples) {
      for (const c of sample) {
        expect(c.tx, `${c.label} x=${c.tx} out of walkable bounds`).toBeGreaterThanOrEqual(1);
        expect(c.tx, `${c.label} x=${c.tx} out of walkable bounds`).toBeLessThanOrEqual(17);
        expect(c.ty, `${c.label} y=${c.ty} out of walkable bounds`).toBeGreaterThanOrEqual(2);
        expect(c.ty, `${c.label} y=${c.ty} out of walkable bounds`).toBeLessThanOrEqual(9);
      }
    }
  });

  test('bed object (long-duration) remains active for at least 10 real seconds', async ({ page }) => {
    /**
     * The bed has a longer activity duration than the bonsai.
     * Trigger it and confirm it does not prematurely return to idle.
     */
    test.setTimeout(60_000);

    await page.goto('/');
    await waitForEngine(page);

    await page.evaluate(() => {
      window._gameEngine.objectEngine.interact('bed', 'use');
    });

    await page.waitForTimeout(500);
    const activated = await getEngineState(page);
    const bed = activated.objectStates.find(o => o.id === 'bed');
    expect(bed?.state, 'Bed should enter active state after interact').not.toBe('idle');
    console.log(`Bed state after trigger: ${bed?.state}`);

    // After 10s it should still be active (bed duration should be > 10s)
    await page.waitForTimeout(10_000);
    const midCheck = await getEngineState(page);
    const bedMid = midCheck.objectStates.find(o => o.id === 'bed');
    expect(
      bedMid?.state,
      'Bed returned to idle within 10s — activity duration is shorter than expected'
    ).not.toBe('idle');
    console.log(`Bed state at 10s: ${bedMid?.state}`);
  });

  test('multiple objects can be active simultaneously', async ({ page }) => {
    /**
     * Verifies concurrent object usage — two objects triggered at the same time
     * should both transition to active states independently.
     */
    await page.goto('/');
    await waitForEngine(page);

    // Trigger two objects simultaneously
    await page.evaluate(() => {
      window._gameEngine.objectEngine.interact('bonsai', 'use');
      window._gameEngine.objectEngine.interact('tv', 'use');
    });

    await page.waitForTimeout(500);
    const state = await getEngineState(page);
    const bonsai = state.objectStates.find(o => o.id === 'bonsai');
    const tv = state.objectStates.find(o => o.id === 'tv');

    expect(bonsai?.state, 'Bonsai should be active').not.toBe('idle');
    expect(tv?.state, 'TV should be active').not.toBe('idle');
    console.log(`Bonsai: ${bonsai?.state}, TV: ${tv?.state}`);
  });
});

