test('debug.html Pause/Play controls exist and toggle correctly', async ({ page }) => {
  /**
   * The debug dashboard shows a "▮▮ Pause" button when the sim is running.
   * Clicking it should toggle to "▶ Play" (paused state).
   * Clicking again should return to "▮▮ Pause" (running state).
   * Button labels: "▮▮ Pause" (running) ↔ "▶ Play" (paused)
   */
  await page.goto(DEBUG_URL);
  await page.waitForFunction(
    () => /Pause|Play/.test(document.body.innerText),
    { timeout: 15_000 }
  );

  // Sim should start running (Pause button visible)
  const initialText = await page.evaluate(() => document.body.innerText);
  expect(initialText, 'Pause button expected when sim is running').toContain('Pause');

  // Click Pause → sim should stop (Play button appears)
  const pauseBtn = page.getByRole('button', { name: /Pause/i });
  await expect(pauseBtn).toBeVisible();
  await pauseBtn.click();
  await page.waitForTimeout(500);

  const afterPause = await page.evaluate(() => document.body.innerText);
  expect(afterPause, 'After clicking Pause, Play button should appear').toContain('Play');

  // Click Play → sim should resume (Pause button appears again)
  const playBtn = page.getByRole('button', { name: /Play/i });
  await expect(playBtn).toBeVisible();
  await playBtn.click();
  await page.waitForTimeout(500);

  const afterResume = await page.evaluate(() => document.body.innerText);
  expect(afterResume, 'After clicking Play, Pause button should reappear').toContain('Pause');

  console.log('Pause/Play toggle confirmed — sim pauses and resumes correctly');
});

